import{_ as t,c as p,o as e,d as o}from"./app.f1e4bbc1.js";var a="/assets/IMG_0097.3638315d.jpg",r="/assets/IMG_0095.f73f2ed5.jpg",s="/assets/shkaf-s-chemodanami.8bcdd012.jpg",_="/assets/IMG_7892.25bcfee6.jpg",c="/assets/IMG_7888.cb3cd348.jpg";const h='{"title":"\u041D\u0430\u0447\u0430\u043B\u043E OOLEY42","description":"","frontmatter":{"title":"\u041D\u0430\u0447\u0430\u043B\u043E OOLEY42","date":"2014-10-30","cover":"IMG_7889.jpg"},"headers":[],"relativePath":"practice/ooley42/begin/index.md"}',i={},l=o('<p>\u041F\u043E\u0447\u0442\u0438 \u043F\u0435\u0440\u0435\u0434 \u043A\u0430\u0436\u0434\u044B\u043C, \u043A\u0442\u043E \u043A\u043E\u0433\u0434\u0430-\u043D\u0438\u0431\u0443\u0434\u044C \u043F\u0440\u043E\u0431\u043E\u0432\u0430\u043B \u0434\u0435\u043B\u0430\u0442\u044C \u0447\u0442\u043E-\u0442\u043E \u0440\u0443\u043A\u0430\u043C\u0438,\xA0\u043D\u0435 \u0440\u0430\u0437 \u0432\u0441\u0442\u0430\u0432\u0430\u043B\u0430 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u044C \u043F\u043E\u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0432 \u043F\u043E\u043B\u043D\u043E\u0446\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439. \u0428\u0438\u0442\u044C\u0435 \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432 \u043F\u044B\u0442\u043A\u0443 \u0435\u0441\u043B\u0438 \u043D\u0435\u0442 \u043D\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0440\u0430\u0441\u043A\u0440\u043E\u0435\u0447\u043D\u043E\u0433\u043E \u0441\u0442\u043E\u043B\u0430 \u0438 \u0443\u0434\u043E\u0431\u043D\u043E\u0433\u043E \u043C\u0435\u0441\u0442\u0430, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u043C\u0430\u0448\u0438\u043D\u043A\u0443. \u0420\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0441 \u0434\u0435\u0440\u0435\u0432\u043E\u043C \u0432 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445 \u0433\u043E\u0440\u043E\u0434\u0441\u043A\u043E\u0439 \u043A\u0432\u0430\u0440\u0442\u0438\u0440\u044B \u043F\u043E\u0447\u0442\u0438 \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0438\u0437-\u0437\u0430 \u0441\u0442\u0440\u0443\u0436\u043A\u0438 \u0438 \u043F\u044B\u043B\u0438. \u0410 \u043D\u0430 \u043A\u0430\u043A\u0438\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0443\u0445\u0438\u0449\u0440\u0435\u043D\u0438\u044F \u043D\u0435 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0438\u0434\u0442\u0438 \u0442\u0435\u043C, \u043A\u0442\u043E \u0441\u043E\u0431\u0440\u0430\u043B\u0441\u044F \u043F\u043E\u043A\u0440\u044B\u0442\u044C \u0447\u0442\u043E-\u043D\u0438\u0431\u0443\u0434\u044C \u043B\u0430\u043A\u043E\u043C \u0438\u043B\u0438 \u044D\u043C\u0430\u043B\u044C\u044E!</p><p><img src="'+a+'" alt=""></p><blockquote><p>\u0418\u043D\u043E\u0433\u0434\u0430 \u043A\u0430\u0436\u0435\u0442\u0441\u044F, \u0447\u0442\u043E \u043C\u0435\u0433\u0430\u043F\u043E\u043B\u0438\u0441\u044B \u0432\u043E\u043E\u0431\u0449\u0435 \u043D\u0435 \u043F\u0440\u0435\u0434\u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u044B \u0434\u043B\u044F \u043F\u043E\u043B\u043D\u043E\u0446\u0435\u043D\u043D\u043E\u0439 \u0436\u0438\u0437\u043D\u0438</p></blockquote><p>\u0422\u0430\u043A\u0438\u0435 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u044B \u0432\u0441\u0442\u0430\u044E\u0442 \u043F\u043E\u0447\u0442\u0438 \u043F\u0435\u0440\u0435\u0434 \u043A\u0430\u0436\u0434\u044B\u043C. \u041D\u043E \u0434\u0430\u043B\u0435\u043A\u043E \u043D\u0435 \u043A\u0430\u0436\u0434\u044B\u0439 \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u0445\u0432\u0430\u0441\u0442\u0430\u0442\u044C\u0441\u044F \u043D\u0430\u043B\u0438\u0447\u0438\u0435\u043C \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439.\xA0\u0427\u0442\u043E \u043C\u044B \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u043C \u043F\u043E\u0434 \u044D\u0442\u0438\u043C \u0441\u043B\u043E\u0432\u043E\u043C? \u0411\u043E\u043B\u044C\u0448\u043E\u0439 \u0441\u0442\u043E\u043B, \u0445\u043E\u0440\u043E\u0448\u0435\u0435 \u043E\u0441\u0432\u0435\u0449\u0435\u043D\u0438\u0435, \u043D\u0430\u043B\u0438\u0447\u0438\u0435 \u0432\u0441\u0435\u0445 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u044B\u0445 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0441\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043D\u0430 \u0437\u0430\u0434\u0430\u0447\u0435 \u0438 \u0441\u043C\u0435\u043B\u043E \u043F\u044B\u043B\u0438\u0442\u044C \u0438 \u0448\u0443\u043C\u0435\u0442\u044C \u043D\u0435 \u043E\u043F\u0430\u0441\u0430\u044F\u0441\u044C \u0432\u044B\u0437\u0432\u0430\u0442\u044C \u043A\u0430\u043A\u0438\u0435-\u0442\u043E \u043D\u0435\u0443\u0434\u043E\u0431\u0441\u0442\u0432\u0430 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0438\u0445.</p><p>\u041C\u044B \u0436\u0438\u0432\u0435\u043C \u0432 \u041C\u043E\u0441\u043A\u0432\u0435 \u0438 \u043D\u0435 \u043F\u043E\u043D\u0430\u0441\u043B\u044B\u0448\u043A\u0435 \u0437\u043D\u0430\u0435\u043C, \u0447\u0442\u043E \u0442\u0430\u043A\u043E\u0435 \u0434\u043E\u0440\u043E\u0433\u0430\u044F \u043D\u0435\u0434\u0432\u0438\u0436\u0438\u043C\u043E\u0441\u0442\u044C. \u0410\u0440\u0435\u043D\u0434\u043E\u0432\u0430\u0442\u044C \u0434\u0430\u0436\u0435 \u043C\u0430\u043B\u0435\u043D\u044C\u043A\u0438\u0439 \u0443\u0433\u043E\u043B\u043E\u043A \u0432 \u043A\u0430\u043A\u043E\u043C-\u043D\u0438\u0431\u0443\u0434\u044C \u043F\u043E\u0434\u0432\u0430\u043B\u0435 \u0432 \u0440\u0430\u0439\u043E\u043D\u0435 \u043F\u0430\u0440\u044B \u0441\u0442\u0430\u043D\u0446\u0438\u0439 \u043C\u0435\u0442\u0440\u043E \u043E\u0442 \u043A\u043E\u043B\u044C\u0446\u0435\u0432\u043E\u0439 \u043B\u0438\u043D\u0438\u0438\xA0\u043C\u043E\u0436\u0435\u0442 \u0441\u0442\u043E\u0438\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0435, \u0447\u0435\u043C \u0441\u0440\u0435\u0434\u043D\u044F\u044F \u0437\u0430\u0440\u043F\u043B\u0430\u0442\u0430 \u0433\u043E\u0440\u043E\u0436\u0430\u043D\u0438\u043D\u0430. \u0412 \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u0433\u043E\u0440\u043E\u0434\u0441\u043A\u043E\u0439 \u0437\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u0435 \u043F\u0440\u0435\u0434\u0443\u0441\u043C\u043E\u0442\u0440\u0435\u043D\u044B \u043F\u043B\u043E\u0449\u0430\u0434\u0438 \u0434\u043B\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0438\u0445 \u0447\u0430\u0441\u0442\u043D\u044B\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0445, \u043D\u0443 \u043A\u0440\u043E\u043C\u0435 \u0440\u0430\u0437\u0432\u0435 \u0447\u0442\u043E \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u043D\u044B\u0445 \u0431\u0430\u043B\u043A\u043E\u043D\u043E\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u0435\u0433\u043E\u0434\u043D\u044F \u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u0446\u0435\u043D\u0442\u0440\u043E\u043C\xA0\u0434\u043B\u044F \u0432\u0441\u0435\u0433\u043E DIY-\u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F.</p><p>\u041E\u0434\u043D\u0430\u043A\u043E \u0434\u0430\u043B\u0435\u043A\u043E \u043D\u0435 \u0443 \u0432\u0441\u0435\u0445 \u0435\u0441\u0442\u044C \u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0438\u0439 \u0431\u0430\u043B\u043A\u043E\u043D \u0438 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0442\u0435\u0440\u043F\u0435\u043B\u0438\u0432\u044B\u0435 \u0441\u043E\u0441\u0435\u0434\u0438, \u0433\u043E\u0442\u043E\u0432\u044B\u0435 \u043F\u0435\u0440\u0435\u043D\u043E\u0441\u0438\u0442\u044C \u043F\u043E\u0447\u0442\u0438 \u0432\u0441\u0435\u0433\u0434\u0430 \u0441\u043E\u043F\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0443 \u0448\u0443\u043C, \u043F\u044B\u043B\u044C \u0438 \u0437\u0430\u043F\u0430\u0445\u0438. \u0411\u0435\u0437\u0432\u044B\u0445\u043E\u0434\u043D\u0430\u044F \u043D\u0430 \u043F\u0435\u0440\u0432\u044B\u0439 \u0432\u0437\u0433\u043B\u044F\u0434 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044F. \u041D\u043E\xA0\u043C\u044B \u0432\u0435\u0440\u0438\u043C, \u0447\u0442\u043E \u0438\u0437 \u043B\u044E\u0431\u043E\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 \u0432\u0441\u0435\u0433\u0434\u0430 \u043C\u043E\u0436\u043D\u043E \u043D\u0430\u0439\u0442\u0438 \u0432\u044B\u0445\u043E\u0434. \u0418 \u043E\u043D \u043D\u0430\u0448\u0435\u043B\u0441\u044F!</p><p><img src="'+r+'" alt=""></p><blockquote><p>\u0422\u0430\u043A\u043E\u0439 \u0430\u0432\u0442\u043E\u0434\u043E\u043C \u0435\u0449\u0435 \u0438 \u0435\u0437\u0434\u0438\u0442\u044C \u0441\u0430\u043C \u0443\u043C\u0435\u0435\u0442, \u043D\u043E \u043D\u0430\u043C \u0442\u0430\u043A\u043E\u0435 \u043D\u0435 \u043E\u0447\u0435\u043D\u044C \u043D\u0443\u0436\u043D\u043E</p></blockquote><p>\u0417\u0430\u043A\u043E\u043F\u0430\u0432\u0448\u0438\u0441\u044C \u0432 \u0438\u043D\u0442\u0435\u0440\u043D\u0435\u0442, \u0430 \u0442\u043E\u0447\u043D\u0435\u0435 \u0432 \u0441\u0430\u0439\u0442\u044B \u0432\u0440\u043E\u0434\u0435 <a href="http://motorhome.auto.ru/trailers/" title="auto.ru" class="external-link" target="_blank" rel="noopener noreferrer">www.auto.ru</a>, \u043C\u044B \u0431\u044B\u0441\u0442\u0440\u043E \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u043B\u0438, \u0447\u0442\u043E \u0437\u0430 \u0441\u0440\u0430\u0432\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0443\u044E \u0441\u0443\u043C\u043C\u0443 \u043C\u043E\u0436\u043D\u043E \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0441\u0442\u0438 \u0441\u0435\u0431\u0435 &quot;\u0431\u0430\u043B\u043A\u043E\u043D&quot; \u0434\u043E\u0432\u043E\u043B\u044C\u043D\u043E \u0432\u043D\u0443\u0448\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u0440\u0430\u0437\u043C\u0435\u0440\u043E\u0432. \u041A \u0442\u043E\u043C\u0443 \u0436\u0435 \u043F\u0435\u0440\u0435\u0434\u0432\u0438\u0436\u043D\u043E\u0439, \u0441 \u0433\u0430\u0437\u043E\u0432\u043E\u0439 \u043F\u043B\u0438\u0442\u043E\u0439 \u0438 \u043E\u0431\u043E\u0433\u0440\u0435\u0432\u0430\u0442\u0435\u043B\u0435\u043C, \u0440\u0430\u043A\u043E\u0432\u0438\u043D\u043E\u0439, \u0442\u0443\u0430\u043B\u0435\u0442\u043E\u043C, \u0432\u043C\u0435\u0441\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u0448\u043A\u0430\u0444\u043E\u043C \u0438 \u0434\u0432\u0443\u043C\u044F \u0431\u043E\u043B\u044C\u0448\u0438\u043C\u0438 \u0441\u0442\u043E\u043B\u0430\u043C\u0438, \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0438\u0440\u0443\u044E\u0449\u0438\u043C\u0438\u0441\u044F \u043F\u0440\u0438 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u0438 \u0432 \u0441\u043F\u0430\u043B\u044C\u043D\u044B\u0435 \u043C\u0435\u0441\u0442\u0430.\xA0\u0422\u043E, \u0447\u0442\u043E \u043D\u0430\u0434\u043E! \u0427\u0443\u0442\u044C \u043F\u043E\u0434\u043D\u0430\u043A\u043E\u043F\u0438\u0432 \u0434\u0435\u043D\u0435\u0433 \u0438 \u0440\u0435\u0448\u0438\u043C\u043E\u0441\u0442\u0438, \u0430 \u0442\u0430\u043A\u0436\u0435 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u0432 \u043C\u0430\u0448\u0438\u043D\u0443 \u0444\u0430\u0440\u043A\u043E\u043F\u043E\u043C, \u043E\u0434\u043D\u0438\u043C \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u043C \u0444\u0435\u0432\u0440\u0430\u043B\u044C\u0441\u043A\u0438\u043C \u0443\u0442\u0440\u043E\u043C \u043C\u044B \u0437\u0430\u0431\u0440\u0430\u043B\u0438 \u043D\u0430\u0448 \u043F\u0440\u0438\u0446\u0435\u043F \u0441 \u043D\u043E\u043C\u0435\u0440\u043E\u043C 42 \u043D\u0430 \u0431\u043E\u0440\u0442\u0443 \u0432 \u0440\u0430\u0439\u043E\u043D\u0435 \u0414\u043E\u043C\u043E\u0434\u0435\u0434\u043E\u0432\u0430.</p><p>\u0414\u043B\u044F \u0443\u0434\u043E\u0431\u043D\u043E\u0439 \u0440\u0430\u0431\u043E\u0442\u044B \u043C\u044B \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u043B\u0438 \u0432\u043D\u0443\u0442\u0440\u0438 \u0434\u0432\u0430 \u043C\u043E\u0449\u043D\u044B\u0445 \u0430\u043A\u043A\u0443\u043C\u0443\u043B\u044F\u0442\u043E\u0440\u0430, \u043F\u0438\u0442\u0430\u044E\u0449\u0438\u0445 \u0441\u0432\u0435\u0442\u043E\u0434\u0438\u043E\u0434\u043D\u043E\u0435 \u043E\u0441\u0432\u0435\u0449\u0435\u043D\u0438\u0435 \u043D\u0430\u0434 \u0440\u0430\u0431\u043E\u0447\u0438\u043C\u0438 \u0441\u0442\u043E\u043B\u0430\u043C\u0438, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0432\u0441\u0435 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u044B\u0435 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043F\u0440\u0438\u0431\u043E\u0440\u044B \u0441 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0435\u043C \u0438\u043D\u0432\u0435\u0440\u0442\u0435\u0440\u0430. \u0423\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E, \u043D\u043E \u043C\u0430\u043B\u0435\u043D\u044C\u043A\u0430\u044F \u043A\u043E\u0440\u043E\u0431\u043E\u0447\u043A\u0430 \u0441 \u043D\u0430\u0434\u043F\u0438\u0441\u044C\u044E 300W \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 \u0434\u043E\u0432\u043E\u043B\u044C\u043D\u043E \u0434\u043E\u043B\u0433\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0434\u0430\u0436\u0435 \u0441 \u043C\u043E\u0449\u043D\u044B\u043C \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043B\u043E\u0431\u0437\u0438\u043A\u043E\u043C \u0438\u043B\u0438 \u0448\u043B\u0438\u0444\u043C\u0430\u0448\u0438\u043D\u043A\u043E\u0439!</p><p>\u041C\u044B \u043D\u0430\u0448\u043B\u0438 \u043E\u0433\u0440\u043E\u043C\u043D\u044B\u0439 \u0448\u043A\u0430\u0444 \u0438 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E\xA0\u043F\u043E\u043B\u043E\u0447\u0435\u043A, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u043C\u043E\u0433\u043B\u0438 \u0432\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0446\u0435\u043B\u044B\u0439 \u0447\u0435\u043C\u043E\u0434\u0430\u043D \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u043A\u0440\u0430\u0441\u043E\u043A, \u0447\u0435\u043C\u043E\u0434\u0430\u043D \u0440\u0430\u0437\u043D\u044B\u0445 \u0432\u0438\u0434\u043E\u0432 \u0431\u0443\u043C\u0430\u0433\u0438, \u044F\u0449\u0438\u043A \u0441 \u043D\u043E\u0436\u043D\u0438\u0446\u0430\u043C\u0438 \u0438 \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u043C\u0438 \u0440\u0435\u0437\u0430\u043A\u0430\u043C\u0438, \u044F\u0449\u0438\u043A \u0441 \u043A\u043B\u0435\u044F\u043C\u0438 \u0438 \u043A\u043B\u0435\u0439\u043A\u0438\u043C\u0438 \u043B\u0435\u043D\u0442\u0430\u043C\u0438, \u043F\u0430\u0440\u0443 \u043F\u0430\u043A\u0435\u0442\u043E\u0432 \u0441 \u0442\u043A\u0430\u043D\u044F\u043C\u0438, \u0448\u0432\u0435\u0439\u043D\u0443\u044E \u043C\u0430\u0448\u0438\u043D\u043A\u0443, \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0434\u043B\u044F \u0440\u0430\u0431\u043E\u0442\u044B \u0441 \u0434\u0435\u0440\u0435\u0432\u043E\u043C \u0438 \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u043C\u0438 \u043A\u0440\u0435\u043F\u0435\u0436\u0430\u043C\u0438, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0446\u0435\u043B\u0443\u044E \u0433\u043E\u0440\u0443 \u043A\u0440\u0430\u0441\u043E\u043A \u0438 \u043B\u0430\u043A\u043E\u0432 \u0432 \u0431\u0430\u043B\u043B\u043E\u043D\u0430\u0445. \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u0432\u043D\u0443\u0442\u0440\u0438 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0433\u043E \u043F\u0440\u0438\u0446\u0435\u043F\u0430 \u0432\u0441\u0435\u043C \u044D\u0442\u0438\u043C \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0432\u0440\u044F\u0434 \u043B\u0438 \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u0441\u044F, \u043D\u043E \u0434\u043B\u044F \u044D\u0442\u0438\u0445 \u0446\u0435\u043B\u0435\u0439 \u0441\u043D\u0430\u0440\u0443\u0436\u0438 \u0435\u0441\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u0432\u044B\u0434\u0432\u0438\u0436\u043D\u043E\u0439 \u0442\u0435\u043D\u0442 \u0438 \u0434\u0430\u0436\u0435 \u043F\u0440\u0438\u0441\u0442\u044F\u0436\u043D\u0430\u044F \u043F\u0430\u043B\u0430\u0442\u043A\u0430 \u043D\u0430 \u0441\u043B\u0443\u0447\u0430\u0439 \u0441\u0435\u0440\u044C\u0435\u0437\u043D\u043E\u0439 \u043D\u0435\u043F\u043E\u0433\u043E\u0434\u044B.</p><p>\u041C\u043E\u0436\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C, \u0447\u0442\u043E \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0430 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u0440\u0435\u0448\u0435\u043D\u0430. \u041D\u043E \u043C\u044B \u0441\u0442\u0430\u0432\u0438\u043C \u0441\u0432\u043E\u0435\u0439 \u0446\u0435\u043B\u044C\u044E \u043D\u0435 \u043E\u0431\u043B\u0435\u0433\u0447\u0435\u043D\u0438\u0435 \u0441\u0432\u043E\u0435\u0439 \u043B\u0438\u0447\u043D\u043E\u0439 \u0441\u0443\u0434\u044C\u0431\u044B \u0438 \u043D\u0435 \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435 \u0441\u0432\u043E\u0435\u0439 \u043C\u0430\u043B\u0435\u043D\u044C\u043A\u043E\u0439 \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u043E\u0439 \u043B\u0430\u0432\u043E\u0447\u043A\u0438. \u041D\u0430\u043C \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u043E \u043F\u043E\u043C\u043E\u0447\u044C \u043A\u0430\u0436\u0434\u043E\u043C\u0443!</p><p><img src="'+s+'" alt=""></p><blockquote><p>\u0427\u0435\u043C\u043E\u0434\u0430\u043D\u044B \u0441 \u043A\u0440\u0430\u0441\u043A\u0430\u043C\u0438 \u0438 \u0431\u0443\u043C\u0430\u0433\u043E\u0439 \u0432\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F \u0432 \u0448\u043A\u0430\u0444 \u0441 \u0442\u043E\u0447\u043D\u043E\u0441\u0442\u044C\u044E \u0432 \u043C\u0438\u043B\u043B\u0438\u043C\u0435\u0442\u0440\u044B</p></blockquote><p>\u041A\u0430\u043A \u043E\u043A\u0430\u0437\u0430\u043B\u043E\u0441\u044C, \u0434\u0430\u0436\u0435 \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0439 \u0440\u0430\u0431\u043E\u0442\u044B\xA0\u0432 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439,\xA0\u043D\u0435 \u0433\u043E\u0432\u043E\u0440\u044F \u0443\u0436 \u043E \u0441\u043F\u043E\u0440\u0430\u0434\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u043D\u0430\u0431\u0435\u0433\u0430\u0445 \u0432 \u043F\u0435\u0440\u0435\u0440\u044B\u0432\u0430\u0445 \u043C\u0435\u0436\u0434\u0443 \u0440\u0430\u0431\u043E\u0447\u0438\u043C\u0438 \u0431\u0443\u0434\u043D\u044F\u043C\u0438, \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432 \u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0435\u0441\u043B\u0438 \u043D\u0435 \u043B\u0438\u0448\u043D\u0438\u043C\u0438, \u0442\u043E \u043C\u0430\u043B\u043E\u0432\u043E\u0441\u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u043D\u044B\u043C\u0438 \u0438 \u043C\u043E\u0433\u0443\u0442 \u043B\u0435\u0436\u0430\u0442\u044C \u0431\u0435\u0437 \u0434\u0435\u043B\u0430 \u043C\u0435\u0441\u044F\u0446\u0430\u043C\u0438. \u041C\u043E\u043B\u043E\u0442\u043E\u043A \u043C\u043E\u0436\u0435\u0442 \u0437\u0430\u0431\u0438\u0442\u044C \u0442\u044B\u0441\u044F\u0447\u0438 \u0438 \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u044B \u0433\u0432\u043E\u0437\u0434\u0435\u0439, \u043D\u043E \u043C\u044B \u043D\u0435 \u0442\u0430\u043A \u0443\u0436 \u0447\u0430\u0441\u0442\u043E \u044D\u0442\u043E \u0434\u0435\u043B\u0430\u0435\u043C, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043D\u043E\u0446\u0435\u043D\u043D\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u044D\u0442\u043E\u0442 \u043F\u043E\u0442\u0435\u043D\u0446\u0438\u0430\u043B. \xA0\u0427\u0442\u043E \u0443\u0436 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u043E \u0434\u043E\u0432\u043E\u043B\u044C\u043D\u043E \u043D\u0430\u0434\u0435\u0436\u043D\u044B\u0445 \u0438 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0445 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u0445. \u0422\u0430\u043A\u0436\u0435 \u0438\u043C\u0435\u044E\u0442 \u0441\u0432\u043E\u0439\u0441\u0442\u0432\u043E \u0441\u043A\u0430\u043F\u043B\u0438\u0432\u0430\u0442\u044C\u0441\u044F &quot;\u043D\u0430 \u0431\u0443\u0434\u0443\u0449\u0435\u0435&quot; \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044B \u0438 \u0438\u0445 \u043E\u0441\u0442\u0430\u0442\u043A\u0438. \u0414\u043B\u044F \u043F\u043E\u043A\u0440\u044B\u0442\u0438\u044F \u043B\u0430\u043A\u043E\u043C \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0433\u043E \u043A\u0443\u043B\u043E\u043D\u0430 \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442\u0441\u044F \u0431\u043E\u043B\u044C\u0448\u0430\u044F \u0431\u0430\u043D\u043A\u0430 \u043B\u0430\u043A\u0430, \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u043F\u043E\u0442\u043E\u043C \u0435\u0449\u0435 \u043D\u0443\u0436\u043D\u043E \u043A\u0443\u0434\u0430-\u0442\u043E \u043F\u0440\u0438\u043C\u0435\u043D\u0438\u0442\u044C. \u0410 \u043E\u0441\u0442\u0430\u0442\u043A\u043E\u0432 \u0434\u0435\u0440\u0435\u0432\u0430 \u043F\u043E\u0441\u043B\u0435 \u043D\u0430\u043F\u0438\u043B\u0438\u0432\u0430\u043D\u0438\u044F \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u0438\u0445 \u043F\u043E\u043B\u043E\u0447\u0435\u043A \u043C\u043E\u0436\u0435\u0442 \u0445\u0432\u0430\u0442\u0438\u0442\u044C \u043D\u0430 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435 \u0446\u0435\u043B\u043E\u0439 \u0433\u043E\u0440\u044B \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u0434\u0435\u0440\u0435\u0432\u044F\u043D\u043D\u044B\u0445 \u043F\u043E\u0434\u0435\u043B\u043E\u043A.</p><p>\u0415\u0449\u0435 \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u0435\u0435 \u043E\u043A\u0430\u0437\u0430\u043B\u0430\u0441\u044C \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044F \u0441\xA0\u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u043C\u0438\xA0\u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430. \u0412\u043E\u0442 \u043F\u043E\u0441\u0435\u0442\u0438\u043B\u0430 \u0433\u043E\u043B\u043E\u0432\u0443 \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u0430\u044F \u0437\u0430\u0434\u0443\u043C\u043A\u0430, \u0432\u043E\u0442 \u0442\u044B \u0443\u0436\u0435 \u043D\u043E\u0441\u0438\u0448\u044C\u0441\u044F \u043F\u043E \u0433\u043E\u0440\u043E\u0434\u0443 \u0432 \u043F\u043E\u0438\u0441\u043A\u0430\u0445 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u044B\u0445 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432 \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432, \u043F\u0440\u044F\u0447\u0435\u0448\u044C\u0441\u044F \u0432 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u0438 \u0434\u0435\u043B\u0430\u0435\u0448\u044C-\u0434\u0435\u043B\u0430\u0435\u0448\u044C-\u0434\u0435\u043B\u0430\u0435\u0448\u044C \u044D\u0442\u043E\u0442 \u043E\u0447\u0430\u0440\u043E\u0432\u0430\u0432\u0448\u0438\u0439 \u0442\u0435\u0431\u044F \u043F\u0440\u043E\u0435\u043A\u0442. \u041F\u0440\u043E\u0435\u043A\u0442 \u0437\u0430\u043A\u043E\u043D\u0447\u0435\u043D \u0438 \u0432\u043E\u0442 \u0442\u044B \u0434\u0435\u0440\u0436\u0438\u0448\u044C \u0432 \u0440\u0443\u043A\u0430\u0445 \u0435\u0433\u043E \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442, \u0431\u0443\u0434\u044C \u044D\u0442\u043E \u043A\u0430\u043A\u0430\u044F-\u043D\u0438\u0431\u0443\u0434\u044C \u0431\u0435\u0437\u0434\u0435\u043B\u0443\u0448\u043A\u0430 \u0438\u043B\u0438 \u0446\u0435\u043B\u044B\u0439 \u0441\u0442\u0443\u043B \u0438, \u0432\u0434\u0440\u0443\u0433, \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0448\u044C, \u0447\u0442\u043E \u0442\u044B \u0432\u043E\u0432\u0441\u0435 \u0438 \u043D\u0435 \u0441\u0442\u0440\u0435\u043C\u0438\u043B\u0441\u044F \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u044D\u0442\u0443 \u0432\u0435\u0449\u044C, \u0430 \u043F\u0440\u043E\u0441\u0442\u043E \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u043B\u0441\u044F \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u043E\u043C \u0441\u0430\u043C\u0438\u043C \u043F\u043E \u0441\u0435\u0431\u0435.\xA0\u0425\u043E\u0440\u043E\u0448\u043E, \u0435\u0441\u043B\u0438 \u0442\u044B \u0434\u0435\u043B\u0430\u043B \u0447\u0442\u043E-\u0442\u043E \u0438\u0437 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0442\u0435\u0431\u0435 \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u043F\u0440\u0438\u0433\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u0431\u044B\u0442\u0443. \u041D\u0443 \u0438\u043B\u0438 \u0435\u0441\u043B\u0438 \u0442\u0435\u0431\u0435 \u0435\u0441\u0442\u044C \u043A\u043E\u043C\u0443 \u043F\u043E\u0434\u0430\u0440\u0438\u0442\u044C \u0441\u0432\u043E\u0438 \u043F\u043E\u0434\u0435\u043B\u043A\u0438. \u041A\u0442\u043E-\u0442\u043E \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E \u0434\u0435\u043B\u0430\u0435\u0442 \u0432\u0435\u0449\u0438 \u0442\u043E\u043B\u044C\u043A\u043E \u043D\u0430 \u043F\u0440\u043E\u0434\u0430\u0436\u0443, \u043A\u043E\u043C\u0443-\u0442\u043E \u0443\u0434\u0430\u0435\u0442\u0441\u044F \u043D\u0430\u0439\u0442\u0438 \u043F\u043E\u043A\u0443\u043F\u0430\u0442\u0435\u043B\u044F \u043F\u043E\u0442\u043E\u043C. \u0412\u0441\u0435 \u0441\u043F\u0440\u0430\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u043E-\u0440\u0430\u0437\u043D\u043E\u043C\u0443, \u043D\u043E \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0441\u043E\u0433\u043B\u0430\u0441\u0438\u0442\u0441\u044F \u0441 \u0442\u0435\u043C, \u0447\u0442\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u2014 \u044D\u0442\u043E \u043D\u0435 \u0441\u043A\u043B\u0430\u0434 \u0438 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u044B \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430 \u043D\u0443\u0436\u043D\u043E \u0438\u0437 \u043D\u0435\u0435 \u043A\u0443\u0434\u0430-\u0442\u043E \u0434\u0435\u0432\u0430\u0442\u044C \u0447\u0442\u043E\u0431\u044B \u043E\u0441\u0432\u043E\u0431\u043E\u0434\u0438\u0442\u044C \u043C\u0435\u0441\u0442\u043E \u0434\u043B\u044F \u043D\u043E\u0432\u044B\u0445 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432.</p><p><img src="'+_+'" alt=""></p><blockquote><p>\u0412 2013 \u0433\u043E\u0434\u0443 \u043F\u0430\u0440\u043A\u043E\u0432\u043A\u0430 \u0432 \u0446\u0435\u043D\u0442\u0440\u0435 \u041C\u043E\u0441\u043A\u0432\u044B \u0435\u0449\u0435 \u043D\u0435 \u0431\u044B\u043B\u0430 \u043F\u043B\u0430\u0442\u043D\u043E\u0439.</p></blockquote><p>\u0412\u0441\u0435 \u044D\u0442\u0438 \u043D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u044F \u043D\u0430\u0432\u0435\u043B\u0438 \u043D\u0430\u0441 \u043D\u0430 \u043C\u044B\u0441\u043B\u0438 \u043E \u0442\u043E\u043C, \u0447\u0442\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u2014 \u044D\u0442\u043E \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u0435 \u0438 \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u043D\u0430\u0431\u043E\u0440 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432. \u041C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u2014 \u044D\u0442\u043E \u0446\u0435\u043B\u0430\u044F \u044D\u043A\u043E\u0441\u0438\u0441\u0442\u0435\u043C\u0430, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043F\u0440\u0438\u0447\u0443\u0434\u043B\u0438\u0432\u043E \u043F\u0435\u0440\u0435\u043F\u043B\u0435\u0442\u0430\u044E\u0442\u0441\u044F \u043F\u043E\u0442\u043E\u043A\u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432, \u0441\u0442\u0440\u0443\u044F\u0449\u0438\u0435\u0441\u044F \u0432 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u043A\u0443\u0449\u0430\u0445 \u0447\u0442\u043E\u0431\u044B \u0432 \u043E\u0434\u0438\u043D \u043C\u043E\u043C\u0435\u043D\u0442 \u0441\u0442\u0430\u0442\u044C \u0437\u0430\u043A\u043E\u043D\u0447\u0435\u043D\u043D\u044B\u043C\u0438 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u043C\u0438 \u0438 \u043F\u043E\u043A\u0438\u043D\u0443\u0442\u044C \u0435\u0435, \u043D\u0430\u0439\u0434\u044F \u0441\u0435\u0431\u0435 \u043D\u043E\u0432\u044B\u0439 \u0434\u043E\u043C.\xA0\u0418\u043D\u043E\u0433\u0434\u0430 \u043A\u0430\u0436\u0435\u0442\u0441\u044F, \u0447\u0442\u043E \u043D\u0435 \u0442\u044B \u0440\u0435\u0448\u0430\u0435\u0448\u044C, \u0447\u0442\u043E \u0442\u044B \u0431\u0443\u0434\u0435\u0448\u044C \u0434\u0435\u043B\u0430\u0442\u044C \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C, \u0430 \u043F\u0440\u043E\u0441\u0442\u043E \u0437\u043D\u0430\u043D\u0438\u0435 \u043E\u0431 \u0438\u043C\u0435\u044E\u0449\u0438\u0445\u0441\u044F \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0430\u0445 \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u0445, \u0441\u043F\u043B\u0435\u0442\u0430\u044F\u0441\u044C, \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u044E\u0442 \u043E\u0431\u0440\u0430\u0437 \u0442\u043E\u0433\u043E, \u0432\u043E \u0447\u0442\u043E \u044D\u0442\u043E \u0432\u0441\u0435 \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u0442\u044C\u0441\u044F.</p><p>\u041C\u044B \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u043B\u0438 \u0441\u0435\u0431\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0443\u044E,\xA0\u043E\u0442\u043A\u0440\u044B\u0442\u0443\u044E \u0434\u043B\u044F \u0432\u0441\u0435\u0445. \u0422\u0430\u043A\u0443\u044E, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043A\u0430\u0436\u0434\u044B\u0439 \u043C\u043E\u0433 \u0431\u044B \u043F\u043E\u0447\u0443\u0432\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0441\u0435\u0431\u044F \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E.\xA0\u041F\u0440\u0438\u043D\u043E\u0441\u0438\u0442\u044C \u0441\u0432\u043E\u0438 \u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u0438\u043C\u0435\u044E\u0449\u0438\u0435\u0441\u044F \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044B \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u043F\u043E \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u0438, \u0441\u043F\u043E\u043A\u043E\u0439\u043D\u043E \u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044F \u0432\u0441\u0435, \u0447\u0442\u043E \u043D\u0435 \u043F\u043E\u0448\u043B\u043E \u0432 \u0434\u0435\u043B\u043E, \u0437\u043D\u0430\u044F, \u0447\u0442\u043E \u044D\u0442\u043E \u0432\u043F\u043E\u043B\u043D\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u043F\u0440\u0438\u0433\u043E\u0434\u0438\u0442\u0441\u044F \u043A\u043E\u043C\u0443-\u0442\u043E \u0435\u0449\u0435. \u0412\u044B\u043B\u043E\u0436\u0438\u0442\u044C \u0441\u0432\u043E\u0438 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0435 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u044B \u0432 \u0431\u043E\u043B\u044C\u0448\u0443\u044E \u043E\u0431\u0449\u0443\u044E \u0432\u0438\u0442\u0440\u0438\u043D\u0443 \u0438 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0442\u044C \u0443\u0432\u043B\u0435\u0447\u0435\u043D\u043D\u043E \u0442\u0440\u0443\u0434\u0438\u0442\u044C\u0441\u044F \u0431\u043E\u043A \u043E \u0431\u043E\u043A \u0441 \u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0430\u043C\u0438, \u0443 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0432\u0441\u0435\u0433\u0434\u0430 \u043C\u043E\u0436\u043D\u043E \u043F\u043E\u043F\u0440\u043E\u0441\u0438\u0442\u044C \u0441\u043E\u0432\u0435\u0442\u0430 \u0438\u043B\u0438 \u043F\u043E\u043C\u043E\u0449\u0438.</p><p>\u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u0434\u043B\u044F \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0433\u043E \u0438 \u0443\u043C\u0435\u043B\u043E\u0433\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u043C\u043D\u043E\u0433\u0438\u0445 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u043D\u0443\u0436\u043D\u044B \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u043D\u0430\u0432\u044B\u043A\u0438. \u041C\u044B \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u043B\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0443\u044E, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043A\u0430\u0436\u0434\u044B\u0439 \u043C\u043E\u0433 \u0431\u044B \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u0430\u0442\u044C \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0438\u043C \u043E\u0431 \u0438\u043C\u0435\u044E\u0449\u0438\u0445\u0441\u044F \u0443 \u043D\u0435\u0433\u043E \u043D\u0430\u0432\u044B\u043A\u0430\u0445 \u0438 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E \u043F\u0440\u0435\u043F\u043E\u0434\u0430\u0432\u0430\u0442\u044C \u0438\u0445 \u043A\u0430\u0436\u0434\u043E\u043C\u0443, \u043A\u043E\u0433\u043E \u044D\u0442\u043E \u0437\u0430\u0438\u043D\u0442\u0435\u0440\u0435\u0441\u0443\u0435\u0442. \u0410 \u0442\u0435, \u0432 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u043C\u043E\u0433\u043B\u0438 \u0431\u044B \u0440\u0430\u0437\u0434\u0430\u0432\u0430\u0442\u044C \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u044B\u0435 \u043D\u0430\u0432\u044B\u043A\u0438 \u0434\u0430\u043B\u044C\u0448\u0435, \u0434\u0430\u0432\u0430\u044F \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0432\u0441\u0435 \u0431\u043E\u043B\u044C\u0448\u0435\u043C\u0443 \u0447\u0438\u0441\u043B\u0443 \u043B\u044E\u0434\u0435\u0439 \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u0443\u0442\u044C\u0441\u044F \u043A \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0441\u0432\u043E\u0431\u043E\u0434\u0435 \u0441\u0430\u043C\u043E\u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u044F.</p><p>\u041C\u044B \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u043B\u0438, \u0447\u0442\u043E \u043A\u0430\u0436\u0434\u044B\u0439, \u043A\u0442\u043E \u043F\u043E\u0431\u044B\u0432\u0430\u0435\u0442 \u0432 \u0442\u0430\u043A\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439, \u0442\u0443\u0442 \u0436\u0435 \u043F\u043E\u0439\u043C\u0435\u0442 \u0438 \u043E\u0446\u0435\u043D\u0438\u0442 \u0435\u0451 \u043F\u043E\u043B\u044C\u0437\u0443 \u0438 \u0432\u0430\u0436\u043D\u043E\u0441\u0442\u044C \u0438 \u0441\u0430\u043C \u043E\u0446\u0435\u043D\u0438\u0442 \u0432\u043A\u043B\u0430\u0434, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043C\u043E\u0436\u0435\u0442 \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0434\u043B\u044F \u0435\u0451 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F. \u0427\u0442\u043E\u0431\u044B \u043D\u0435 \u043D\u0443\u0436\u043D\u044B \u0431\u044B\u043B\u0438 \u043D\u0438\u043A\u0430\u043A\u0438\u0435 \u0442\u0430\u0440\u0438\u0444\u044B \u0438 \u0441\u0442\u0430\u0432\u043A\u0438, \u0430 \u0432\u043E\u043A\u0440\u0443\u0433 \u043A\u0430\u0436\u0434\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043B\u043E\u0441\u044C \u0441\u043E\u043E\u0431\u0449\u0435\u0441\u0442\u0432\u043E \u0442\u0435\u0445, \u043A\u0442\u043E \u0432\u0437\u044F\u043B \u043D\u0430 \u0441\u0435\u0431\u044F \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0443\u044E \u0434\u043E\u043B\u044E \u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0437\u0430 \u043D\u0435\u0435 \u0438 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043B \u0431\u044B \u0438 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u043B \u0435\u0451 \u043F\u043E \u043C\u0435\u0440\u0435 \u0441\u0432\u043E\u0438\u0445 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0435\u0439.</p><hr><p><img src="'+c+'" alt=""></p><p>\u0417\u0430\u043C\u0435\u0447\u0442\u0430\u043B\u0438\u0441\u044C? \u0412\u043E\u0437\u043C\u043E\u0436\u043D\u043E. \u041D\u043E\xA0\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u043C\u043D\u043E\u0433\u043E\u0435! \u041F\u0443\u0441\u043A\u0430\u0439 \u043D\u0435 \u0432\u0441\u0435 \u0441\u0440\u0430\u0437\u0443, \u043D\u043E \u043C\u044B \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u043C \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0442\u044C \u043D\u0430\u0434 \u044D\u0442\u0438\u043C\u0438 \u0438\u0434\u0435\u044F\u043C\u0438, \u0430\u043A\u043A\u0443\u0440\u0430\u0442\u043D\u043E \u0438 \u043F\u043E\u044D\u0442\u0430\u043F\u043D\u043E \u043F\u0440\u043E\u0432\u043E\u0434\u044F \u0438\u0445 \u0432 \u0436\u0438\u0437\u043D\u044C. \u041F\u0440\u043E\u0431\u0443\u044F \u0438 \u043D\u0430\u0431\u043B\u044E\u0434\u0430\u044F \u0437\u0430 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u043C\u0438, \u043C\u044B \u043F\u044B\u0442\u0430\u0435\u043C\u0441\u044F \u0432\u044B\u0432\u0435\u0441\u0442\u0438 \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u0443\u044E \u0444\u043E\u0440\u043C\u0443\u043B\u0443 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0445 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u0444\u0438\u043B\u044F. \u0420\u0435\u0446\u0435\u043F\u0442, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044F \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u0438\u043D\u0433\u0440\u0435\u0434\u0438\u0435\u043D\u0442\u043E\u0432, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043F\u043E\u0434\u0431\u043E\u0440\u0430 \u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u044F, \u0437\u0430\u043A\u0443\u043F\u043A\u0438 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u044B\u0445 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0438 \xA0\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E\u0433\u043E \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0430 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432 \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0445 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u043E\u0432, \u043D\u043E \u0438 \u043D\u0435 \u0437\u0430\u0431\u044B\u0432\u0430\u044F \u043E \u0442\u0430\u043A\u0438\u0445 \u0432\u0430\u0436\u043D\u044B\u0445 &quot;\u0441\u043F\u0435\u0446\u0438\u044F\u0445&quot; \u043A\u0430\u043A \u0432\u0438\u0437\u0443\u0430\u043B\u044C\u043D\u043E\u0435 \u043E\u0444\u043E\u0440\u043C\u043B\u0435\u043D\u0438\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439, \u0430 \u0442\u0430\u043A\u0436\u0435 \u043F\u0440\u0430\u0432\u0438\u043B\u0430 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u0438 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F\xA0\u043B\u044E\u0434\u0435\u0439, \u0441\u043F\u043E\u0441\u043E\u0431\u044B \u0440\u0430\u0437\u0440\u0435\u0448\u0435\u043D\u0438\u044F \u0441\u043B\u043E\u0436\u043D\u044B\u0445 \u0438 \u043D\u0435\u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u0443\u0435\u043C\u044B\u0445 \u0432\u043E\u043F\u0440\u043E\u0441\u043E\u0432 \u0438 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0439.</p><p>\u041C\u044B \u0441\u0442\u0430\u0432\u0438\u043C \u043F\u0435\u0440\u0435\u0434 \u0441\u043E\u0431\u043E\u0439 \u0433\u0440\u0430\u043D\u0434\u0438\u043E\u0437\u043D\u044B\u0435 \u0446\u0435\u043B\u0438 \u0438 \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u0431\u043E\u0438\u043C\u0441\u044F. \u0423 \u043D\u0430\u0441 \u0435\u0441\u0442\u044C \u043D\u0430\u0448 \u0432\u0435\u0440\u043D\u044B\u0439 \u043F\u0440\u0438\u0446\u0435\u043F OOLEY42, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0443\u0436\u0435 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0441\u043E\u0431\u043E\u0439 \u0432\u0435\u0441\u044C OOLEY \u0432 \u043C\u0438\u043D\u0438\u0430\u0442\u044E\u0440\u0435. \u0410 \u0437\u043D\u0430\u0447\u0438\u0442 \u0432\u0441\u0435, \u0447\u0442\u043E \u043D\u0430\u043C \u043E\u0441\u0442\u0430\u043B\u043E\u0441\u044C \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u2014 \u043F\u043E\u0434\u0435\u043B\u0438\u0442\u044C\u0441\u044F \u0440\u0430\u0434\u043E\u0441\u0442\u044C\u044E\xA0\u0434\u043E\u0441\u0442\u0443\u043F\u0430 \u043A \u0435\u0433\u043E \u0448\u0438\u0440\u043E\u043A\u0438\u043C \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044F\u043C. \u0418 \u043C\u044B \u0434\u0435\u043B\u0438\u043C\u0441\u044F!</p><p><a href="/practice/ooley42/" title="\u041F\u0440\u0438\u0446\u0435\u043F OOLEY42">\u0417\u0434\u0435\u0441\u044C</a>\xA0\u043C\u043E\u0436\u0435\u0442\u0435 \u043D\u0430\u0439\u0442\u0438 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u043C\u0435\u0441\u0442\u043E\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u043F\u0440\u0438\u0446\u0435\u043F\u0430 \u0438 \u0430\u043D\u043E\u043D\u0441\u044B \u0431\u0443\u0434\u0443\u0449\u0438\u0445 \u0441\u043E\u0431\u044B\u0442\u0438\u0439 \u0432 OOLEY42. \u0417\u0430\u043F\u0438\u0441\u044B\u0432\u0430\u0439\u0442\u0435\u0441\u044C \u0438 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0438\u0442\u044C \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u043D\u0430\u043C\u0438!</p>',27),n=[l];function u(d,m,f,g,q,b){return e(),p("div",null,n)}var O=t(i,[["render",u]]);export{h as __pageData,O as default};
